INSERT INTO `email_settings` VALUES
(11,'DVEPL','mailerbotv3@vibrantick.in','Mailerbotv3@2026','smtp.hostinger.com',465,1,'2025-10-29 07:34:32','2026-02-20 05:09:59',NULL,'ydeep9073@gmail.com','7984561230','Chandigarh',NULL,NULL,NULL);
INSERT INTO `email_template` VALUES
(9,'Welcome Email','Welcome to DVEPL','<p>Dear Sir/Madam,</p><p>Welcome to <em>DVEPL </em>!</p><p> We are delighted to have you with us. Our goal is to make your experience smooth, professional, and efficient.</p><p>You can now explore tenders, submit enquiries, and manage all your business communications easily on our platform.</p><p><strong>Your Registered Firm: </strong>{$firmName}</p><p> <strong>Registered Email: </strong>{$registeredEmail}</p><p>If you have any questions or need help, please don\'t hesitate to contact our support team.</p>','<p><strong>Thanks &amp; Regards,</strong></p><p> DVEPL Team</p><p> Mobile: {$supportPhone}</p><p> Email: {$supportEmail}</p><p> Website: https://dvepl.com/quotetender</p><p>Copyright 2025 DVEPL. All Rights Reserved.</p>','WELCOME','2025-10-30 13:10:14','2025-11-17 10:24:52',1),
(10,'Tender Request Template','Tender Request Notification','<p>Dear Sir/Madam,</p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">Thank you for your valuable enquiry! We truly appreciate your interest. We will provide the pricing details within 3-5 working days for the following tender:</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">Request Id : {$tenderId},</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">Firm Name :   {$firmName}</span></p><p>Name : {$name}</p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">If you have any questions or need further assistance regarding the process, please don\'t hesitate to contact us. We\'re here to help!</span></p>','<p><strong>Thanks &amp; Regards,</strong></p><p> DVEPL Team</p><p> Mobile: {$supportPhone}</p><p> Email: {$supportEmail}</p><p> Website: https://dvepl.com/quotetender</p><p>Copyright 2025 DVEPL. All Rights Reserved.</p>','TENDER_REQUEST','2025-10-31 13:54:24','2025-11-17 10:31:54',1),
(11,'Send Quotation Template','Quotation Attached for Tender ID: {$tenderId}','<p>Dear {$name},</p><p>We are pleased to inform you that for Tender ID: <span style=\"color: rgb(51, 51, 51); background-color: rgb(255, 255, 255);\">{$tenderId}</span>. The quotation file is attached below for your reference.</p><p><br></p><p>If you have any questions or need further assistance regarding the process, feel free to reach out to us. We are here to help!</p>','<p><strong>Thanks &amp; Regards,</strong></p><p> DVEPL Team</p><p> Mobile: {$supportPhone}</p><p> Email: {$supportEmail}</p><p> Website: https://dvepl.com/quotetender</p><p>Copyright 2025 DVEPL. All Rights Reserved.</p>','SENT_TENDER','2025-11-03 09:56:34','2025-11-17 10:32:17',1),
(12,'Alot Tender Template','Congratulation tender is allotted','<p><strong>Dear {$name}</strong>,</p><p> <span style=\"color: rgb(0, 0, 0);\">Congratulations on being declared L1 in the tender .</span><strong> ID</strong>: <span style=\"color: rgb(51, 51, 51); background-color: rgb(255, 255, 255);\">{$tenderId}</span>. <span style=\"color: rgb(0, 0, 0);\">We kindly request You to give us the opportunity to supply the following materials in accordance with your specifications . We assure you of our commitment to quality, compliance, and timely delivery, and we look forward to establishing a successful and long-term association.</span></p><p><br></p><p>VCB\'s</p><p>RMU</p><p>TTA / PTTA Panels</p><p>Feeder Pillars </p><p>PCC / MCC Panels </p><p><br></p><p><br></p><p>If you have any questions or need further assistance regarding the process, feel free to reach out to us. We are here to help!</p>','<p><strong>Thanks &amp; Regards,</strong></p><p> DVEPL Team</p><p> Mobile: {$supportPhone}</p><p> Email: {$supportEmail}</p><p> Website: https://dvepl.com/quotetender</p><p>Copyright 2025 DVEPL. All Rights Reserved.</p>','ALOT_TENDER','2025-11-03 10:16:44','2026-01-04 10:35:00',1),
(13,'Verification Template','Verification with DVEPL','<p>Dear {$name},</p><p>Thank you for registering with DVEPL. Your registration process is completed. Please Click the button  below to active your account.</p><p><br></p><h2>                                                    <a href=\"{$link}\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: rgb(255, 255, 255); background-color: rgb(102, 185, 102);\">Verify</a></h2>','<p><strong>Thanks &amp; Regards,</strong></p><p> DVEPL Team</p><p> Mobile: {$supportPhone}</p><p> Email: {$supportEmail}</p><p> Website: dvepl.com</p><p>Copyright 2025 DVEPL. All Rights Reserved.</p>','VERIFICATION','2025-11-12 11:16:22','2025-11-17 10:32:53',1),
(14,'User Password Reset','Reset Password','<p>Dear User , </p><p>Click the following link to reset your password : <a href=\"{$link}\" rel=\"noopener noreferrer\" target=\"_blank\">Reset Password</a></p>','<p><strong>Thanks &amp; Regards,</strong></p><p> DVEPL Team</p><p> Mobile: {$supportPhone}</p><p> Email: {$supportEmail}</p><p> Website: https://dvepl.com/quotetender</p><p>Copyright 2025 DVEPL. All Rights Reserved.</p>','PASSWORD_RESET','2026-01-30 12:27:04','2026-01-30 12:31:25',1);
